(250, 'default', 'Post updated', 'App\\Models\\CMS\\Post', NULL, 24, 'App\\Models\\User', 1, '{\"changes\": {\"content\": \"<p>The countdown to the most anticipated gospel music event in Kenya has begun. <strong>MEMA Gala 2026</strong> takes place on <strong>September 16, 2026 in Nairobi</strong> — and you can secure your seat today at a special early bird rate.</p><h3>Early Bird Pricing</h3><ul><li><strong>Early Bird Regular Seat</strong> — KES 1,000 (save KES 500 off standard price)</li><li><strong>Early Bird VIP Seat</strong> — KES 2,500 (save KES 1,000 off standard price)</li></ul><p>Early bird tickets are available from April 16 to June 30, 2026. After that, prices revert to standard rates.</p><h3>Standard Pricing (from July 1)</h3><ul><li>Regular Single Seat — KES 1,500</li><li>VIP Single Seat — KES 3,500</li><li>VVIP Single Seat — KES 6,000</li><li>VIP Table (10 seats) — KES 30,000</li><li>VVIP Table (10 seats) — KES 50,000</li></ul><h3>What\'s Included</h3><p>All tickets include a gala dinner and event programme. VIP and VVIP tickets include priority seating. VVIP tickets include VIP lounge access and meet &amp; greet opportunities with award winners.</p><p><a href=\\\"/event-detail?slug=mema-gala-2026\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">Get your tickets now →</a></p>\", \"updated_at\": \"2026-03-26 13:04:45\", \"category_id\": \"1\", \"published_at\": \"2026-03-26 12:20:00\", \"reading_time\": 1, \"featured_image\": \"posts/featured-images/mK4IG7kdfXvuDnbHvsVkmpcYiIB4tdp2pt8cusQX.webp\"}}', NULL, '2026-03-26 10:04:45', '2026-03-26 10:04:45');
INSERT INTO `activity_log` (`id`, `log_name`, `description`, `subject_type`, `event`, `subject_id`, `causer_type`, `causer_id`, `properties`, `batch_uuid`, `created_at`, `updated_at`) VALUES
(251, 'default', 'Post updated', 'App\\Models\\CMS\\Post', NULL, 25, 'App\\Models\\User', 1, '{\"changes\": {\"content\": \"<p>Kenya has a rich, vibrant gospel music scene. From worship anthems that fill stadiums to intimate songs that carry people through personal crises — gospel music is woven into the fabric of Kenyan life.</p><p>Yet for too long, the artists, producers, directors, and photographers behind this music have had no dedicated national awards platform to call their own. MEMA is here to change that.</p><h3>What MEMA Stands For</h3><p><strong>Myogenic Excellence Music Awards</strong> — MEMA is built to recognise and celebrate creative excellence in gospel music. Not popularity alone. Not social media follower counts. True artistry, ministry impact, and craft.</p><h3>9 Categories, 36+ Nominees</h3><p>MEMA 2026 spans 9 award categories covering every dimension of gospel music creation — from performing artists to audio producers, video directors, and photographers. Every voice in the gospel music ecosystem deserves recognition.</p><h3>Powered by the Community</h3><p>Unlike industry-only awards, MEMA is driven by public nominations and voting. The Kenyan gospel music community — fans, church communities, music lovers — decides who wins. Eight out of nine categories are open for public nomination and public voting.</p><h3>The MEMA Gala 2026</h3><p>On <strong>September 16, 2026</strong>, Nairobi will host an unforgettable evening of awards, live performances, and celebration. The MEMA Gala is not just an awards night — it is a declaration that African gospel music excellence deserves its own stage.</p><p>Nominate your favourite artists today. Be part of the story. <a href=\\\"/nominate?event=mema-gala-2026\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">Nominate now →</a></p>\", \"updated_at\": \"2026-03-26 13:07:10\", \"category_id\": \"5\", \"is_featured\": \"1\", \"published_at\": \"2026-03-26 12:20:00\", \"reading_time\": 2, \"featured_image\": \"posts/featured-images/tM3J9fKgek2Jh36hWQAIZMUvLthwyk8NiOoS21qK.webp\"}}', NULL, '2026-03-26 10:07:10', '2026-03-26 10:07:10'),
(252, 'default', 'Post updated', 'App\\Models\\CMS\\Post', NULL, 26, 'App\\Models\\User', 1, '{\"changes\": {\"content\": \"<p>Voting at MEMA 2026 is open to everyone — no registration required. Here\'s how it works:</p><h3>Step 1: Browse the Nominees</h3><p>Visit the <a href=\\\"/nominees\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">Nominees page</a> and browse all shortlisted artists across 9 award categories. Take your time — get to know who has been nominated and what they\'ve achieved.</p><h3>Step 2: Choose Your Vote Bundle</h3><p>MEMA uses a vote bundle system. One vote costs KES 100. You can buy bundles for better value:</p><ul><li>Single Vote — KES 100</li><li>Starter Pack (10 votes) — KES 900</li><li>Fan Pack (50 votes) — KES 4,000 — <strong>Best value!</strong></li><li>Super Fan (100 votes) — KES 7,000</li><li>Champion (500 votes) — KES 30,000</li></ul><h3>Step 3: Pay Securely</h3><p>Complete your payment via M-Pesa or card through our secure payment gateway. Your votes are credited instantly.</p><h3>Step 4: Allocate Your Votes</h3><p>You can spread your votes across multiple nominees and categories. Support the Female Artist AND the Emerging Artist — it\'s your call.</p><h3>When Does Voting Open?</h3><p>Public voting opens on <strong>August 1, 2026</strong> and closes on <strong>September 14, 2026</strong> at 11:59 PM (EAT).</p><p>Mark your calendar — and in the meantime, nominate your favourites so they make it to the voting stage! <a href=\\\"/nominate?event=mema-gala-2026\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">Nominate now →</a></p>\", \"updated_at\": \"2026-03-26 13:08:18\", \"category_id\": \"5\", \"published_at\": \"2026-03-26 12:20:00\", \"reading_time\": 1, \"featured_image\": \"posts/featured-images/W0PFc4KhDlkC4SWDg9HkKK49mfhXiuxdSK6FvXFx.webp\"}}', NULL, '2026-03-26 10:08:18', '2026-03-26 10:08:18'),
(253, 'default', 'Post updated', 'App\\Models\\CMS\\Post', NULL, 22, 'App\\Models\\User', 1, '{\"changes\": {\"content\": \"<p>We are thrilled to announce that <strong>MEMA 2026 — the Myogenic Excellence Music Awards</strong> is officially open for nominations!</p><p>This is Kenya\'s first dedicated gospel music awards platform, celebrating outstanding talent across performance, production, videography, and photography.</p><h3>Who Can Be Nominated?</h3><p>Any Kenyan or African gospel artist, producer, director, or photographer who has made a significant impact in 2025–2026 is eligible for nomination. Eight categories are open for public nomination.</p><h3>How to Nominate</h3><p>Visit our <a href=\\\"/nominate?event=mema-gala-2026\\\" rel=\\\"noopener noreferrer\\\" target=\\\"_blank\\\">Nominate page</a>, select the MEMA Gala 2026 event, choose your category, and fill in the nomination form. Nominations are free and open until July 15, 2026.</p><h3>The Gala</h3><p>The MEMA Gala will be held on <strong>September 16, 2026 in Nairobi, Kenya</strong> — an unforgettable evening of music, awards, and celebration.</p><p>Get your tickets early and join us as we celebrate Africa\'s gospel excellence!</p>\", \"updated_at\": \"2026-03-26 13:08:56\", \"category_id\": \"7\", \"published_at\": \"2026-03-26 12:18:00\", \"reading_time\": 1, \"featured_image\": \"posts/featured-images/kGDAV9WPCRN9DnasyERx4Zlvss9DGHwyyyANsaav.webp\"}}', NULL, '2026-03-26 10:08:56', '2026-03-26 10:08:56'),
