--
-- Table structure for table `commission_splits`
--

CREATE TABLE `commission_splits` (
  `id` bigint UNSIGNED NOT NULL,
  `transaction_id` bigint UNSIGNED NOT NULL,
  `client_id` bigint UNSIGNED NOT NULL,
  `gross_amount` decimal(15,2) NOT NULL,
  `gateway_fee` decimal(10,2) NOT NULL DEFAULT '0.00',
  `gateway_channel` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `commission_rate` decimal(5,2) NOT NULL,
  `platform_commission` decimal(15,2) NOT NULL,
  `client_revenue` decimal(15,2) NOT NULL,
  `vat_amount` decimal(15,2) NOT NULL DEFAULT '0.00',
  `other_fees` decimal(15,2) NOT NULL DEFAULT '0.00',
  `net_client_amount` decimal(15,2) NOT NULL,
  `commission_type` enum('standard','ticketing','voting','refund_reversal') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'standard',
  `applied_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

