--
-- Table structure for table `email_templates`
--

CREATE TABLE `email_templates` (
  `id` bigint UNSIGNED NOT NULL,
  `uuid` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `client_id` bigint UNSIGNED DEFAULT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `category` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `subject` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `body_html` longtext COLLATE utf8mb4_unicode_ci NOT NULL,
  `body_text` longtext COLLATE utf8mb4_unicode_ci,
  `placeholders` json DEFAULT NULL,
  `variables` json DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `is_system` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Dumping data for table `email_templates`
--

INSERT INTO `email_templates` (`id`, `uuid`, `client_id`, `name`, `slug`, `category`, `description`, `subject`, `body_html`, `body_text`, `placeholders`, `variables`, `is_active`, `is_system`, `created_at`, `updated_at`) VALUES
(1, 'e1f7497c-1624-4abf-87a6-e3806257b588', 1, 'Ticket Purchase Confirmation', 'ticket-purchase-confirmation-1', 'ticketing', 'Sent automatically when a ticket purchase is completed.', 'Your ticket for {{event_name}} is confirmed!', '<h2>Your Ticket is Confirmed!</h2>\n<p>Hi {{attendee_name}},</p>\n<p>Great news — your ticket for <strong>{{event_name}}</strong> has been confirmed.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Ticket #</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{ticket_number}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Ticket Type</td><td style=\"padding:8px;border:1px solid #ddd;\">{{ticket_type}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Event Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Amount Paid</td><td style=\"padding:8px;border:1px solid #ddd;\">{{amount_paid}}</td></tr>\n</table>\n<p>Please bring this confirmation or your QR code to the event entrance.</p>\n<p>We look forward to seeing you at <strong>{{event_name}}</strong>!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nYour ticket for {{event_name}} has been confirmed.\n\nTicket #: {{ticket_number}}\nDate: {{event_date}}\nVenue: {{event_venue}}\n\nPlease bring this confirmation or your QR code to the event.\n\nSee you there!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_venue\", \"ticket_number\", \"ticket_type\", \"amount_paid\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(2, 'd605e25e-ce07-4fc7-90b7-8a987dbba6e2', 1, 'Event Registration Confirmation', 'event-registration-confirmation-1', 'registration', 'Sent when a registration is approved or submitted.', 'Registration confirmed — {{event_name}}', '<h2>Registration Confirmed</h2>\n<p>Hi {{attendee_name}},</p>\n<p>Your registration for <strong>{{event_name}}</strong> has been approved.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Event</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{event_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>We\'re excited to have you join us. Please check the event schedule closer to the date.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nYour registration for {{event_name}} has been confirmed.\n\nEvent Date: {{event_date}}\nVenue: {{event_venue}}\n\nWe look forward to seeing you!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(3, 'a4b1a449-56b1-40d7-9a43-540e06605ba1', 1, 'Payment Receipt', 'payment-receipt-1', 'financial', 'Sent when a payment is successfully processed.', 'Payment receipt — {{event_name}}', '<h2>Payment Receipt</h2>\n<p>Hi {{attendee_name}},</p>\n<p>We have successfully received your payment for <strong>{{event_name}}</strong>.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Amount</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{amount}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Transaction ID</td><td style=\"padding:8px;border:1px solid #ddd;\">{{transaction_id}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Payment Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{payment_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Method</td><td style=\"padding:8px;border:1px solid #ddd;\">{{payment_method}}</td></tr>\n</table>\n<p>Please keep this receipt for your records.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nWe have received your payment of {{amount}} for {{event_name}}.\n\nTransaction ID: {{transaction_id}}\nDate: {{payment_date}}\nMethod: {{payment_method}}\n\nThank you!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"amount\", \"transaction_id\", \"payment_date\", \"payment_method\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(4, '660932dd-0e3f-4c89-8b4d-9870622ca4b4', 1, 'Event Reminder — 24 Hours', 'event-reminder-24-hours-1', 'reminder', 'Automatically sent 24 hours before the event starts.', 'Reminder: {{event_name}} is tomorrow!', '<h2>Event Reminder</h2>\n<p>Hi {{attendee_name}},</p>\n<p>This is a friendly reminder that <strong>{{event_name}}</strong> starts in <strong>24 hours</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Time</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_time}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>Don\'t forget to bring your ticket or QR code. See you soon!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nJust a reminder that {{event_name}} starts tomorrow at {{event_time}}.\n\nVenue: {{event_venue}}\n\nDon\'t forget to bring your ticket!\n\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_time\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(5, '2ef36ddc-b98f-4fcf-ac90-835267e707d1', 1, 'Event Reminder — 1 Hour', 'event-reminder-1-hour-1', 'reminder', 'Automatically sent 1 hour before the event starts.', '{{event_name}} starts in 1 hour!', '<h2>Event Reminder</h2>\n<p>Hi {{attendee_name}},</p>\n<p>This is a friendly reminder that <strong>{{event_name}}</strong> starts in <strong>1 hour</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Time</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_time}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>Don\'t forget to bring your ticket or QR code. See you soon!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\n{{event_name}} starts in just 1 hour! Head to {{event_venue}} now.\n\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_time\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(6, '5e824c89-8079-401e-9f0d-765a76bf93d0', 1, 'Voting Confirmation', 'voting-confirmation-1', 'voting', 'Sent when a vote is successfully cast.', 'Your vote has been counted — {{event_name}}', '<h2>Your Vote Has Been Counted!</h2>\n<p>Hi {{voter_name}},</p>\n<p>Thank you for participating in <strong>{{event_name}}</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Voted For</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{nominee_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Category</td><td style=\"padding:8px;border:1px solid #ddd;\">{{category_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Votes Cast</td><td style=\"padding:8px;border:1px solid #ddd;\">{{votes_count}}</td></tr>\n</table>\n<p>Your vote has been securely recorded. Results will be announced at the event.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{voter_name}},\n\nThank you! Your vote for {{nominee_name}} in {{category_name}} has been recorded.\n\nVotes cast: {{votes_count}}\nEvent: {{event_name}}\n\n{{organizer_name}}', '[\"voter_name\", \"nominee_name\", \"category_name\", \"votes_count\", \"event_name\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(7, '965cae8b-06f1-4c3a-9a7e-78ab0c60f39d', 1, 'General Announcement', 'general-announcement-1', 'general', 'A reusable template for general event announcements.', '{{subject_line}}', '<h2>{{subject_line}}</h2>\n<p>Hi {{attendee_name}},</p>\n<p>{{message_body}}</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\n{{message_body}}\n\nRegards,\n{{organizer_name}}', '[\"attendee_name\", \"subject_line\", \"message_body\", \"organizer_name\", \"event_name\"]', NULL, 1, 0, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(8, '8f0417f1-4b97-4b3d-8c1c-276634a36654', 2, 'Ticket Purchase Confirmation', 'ticket-purchase-confirmation-2', 'ticketing', 'Sent automatically when a ticket purchase is completed.', 'Your ticket for {{event_name}} is confirmed!', '<h2>Your Ticket is Confirmed!</h2>\n<p>Hi {{attendee_name}},</p>\n<p>Great news — your ticket for <strong>{{event_name}}</strong> has been confirmed.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Ticket #</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{ticket_number}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Ticket Type</td><td style=\"padding:8px;border:1px solid #ddd;\">{{ticket_type}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Event Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Amount Paid</td><td style=\"padding:8px;border:1px solid #ddd;\">{{amount_paid}}</td></tr>\n</table>\n<p>Please bring this confirmation or your QR code to the event entrance.</p>\n<p>We look forward to seeing you at <strong>{{event_name}}</strong>!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nYour ticket for {{event_name}} has been confirmed.\n\nTicket #: {{ticket_number}}\nDate: {{event_date}}\nVenue: {{event_venue}}\n\nPlease bring this confirmation or your QR code to the event.\n\nSee you there!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_venue\", \"ticket_number\", \"ticket_type\", \"amount_paid\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(9, '1fe7b220-df72-439b-aa58-06cde7c38200', 2, 'Event Registration Confirmation', 'event-registration-confirmation-2', 'registration', 'Sent when a registration is approved or submitted.', 'Registration confirmed — {{event_name}}', '<h2>Registration Confirmed</h2>\n<p>Hi {{attendee_name}},</p>\n<p>Your registration for <strong>{{event_name}}</strong> has been approved.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Event</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{event_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>We\'re excited to have you join us. Please check the event schedule closer to the date.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nYour registration for {{event_name}} has been confirmed.\n\nEvent Date: {{event_date}}\nVenue: {{event_venue}}\n\nWe look forward to seeing you!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(10, '014762fc-4c3d-475c-8934-67e13cef8a4b', 2, 'Payment Receipt', 'payment-receipt-2', 'financial', 'Sent when a payment is successfully processed.', 'Payment receipt — {{event_name}}', '<h2>Payment Receipt</h2>\n<p>Hi {{attendee_name}},</p>\n<p>We have successfully received your payment for <strong>{{event_name}}</strong>.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Amount</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{amount}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Transaction ID</td><td style=\"padding:8px;border:1px solid #ddd;\">{{transaction_id}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Payment Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{payment_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Method</td><td style=\"padding:8px;border:1px solid #ddd;\">{{payment_method}}</td></tr>\n</table>\n<p>Please keep this receipt for your records.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nWe have received your payment of {{amount}} for {{event_name}}.\n\nTransaction ID: {{transaction_id}}\nDate: {{payment_date}}\nMethod: {{payment_method}}\n\nThank you!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"amount\", \"transaction_id\", \"payment_date\", \"payment_method\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(11, '5c7c0039-adf0-460a-a414-e488e6e10cba', 2, 'Event Reminder — 24 Hours', 'event-reminder-24-hours-2', 'reminder', 'Automatically sent 24 hours before the event starts.', 'Reminder: {{event_name}} is tomorrow!', '<h2>Event Reminder</h2>\n<p>Hi {{attendee_name}},</p>\n<p>This is a friendly reminder that <strong>{{event_name}}</strong> starts in <strong>24 hours</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Time</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_time}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>Don\'t forget to bring your ticket or QR code. See you soon!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nJust a reminder that {{event_name}} starts tomorrow at {{event_time}}.\n\nVenue: {{event_venue}}\n\nDon\'t forget to bring your ticket!\n\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_time\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(12, '238f8c4c-1a46-47be-b65f-db2e58e0cb17', 2, 'Event Reminder — 1 Hour', 'event-reminder-1-hour-2', 'reminder', 'Automatically sent 1 hour before the event starts.', '{{event_name}} starts in 1 hour!', '<h2>Event Reminder</h2>\n<p>Hi {{attendee_name}},</p>\n<p>This is a friendly reminder that <strong>{{event_name}}</strong> starts in <strong>1 hour</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Time</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_time}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>Don\'t forget to bring your ticket or QR code. See you soon!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\n{{event_name}} starts in just 1 hour! Head to {{event_venue}} now.\n\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_time\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(13, '8bc0ff7f-2710-4ebf-90f0-a49919f4aa40', 2, 'Voting Confirmation', 'voting-confirmation-2', 'voting', 'Sent when a vote is successfully cast.', 'Your vote has been counted — {{event_name}}', '<h2>Your Vote Has Been Counted!</h2>\n<p>Hi {{voter_name}},</p>\n<p>Thank you for participating in <strong>{{event_name}}</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Voted For</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{nominee_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Category</td><td style=\"padding:8px;border:1px solid #ddd;\">{{category_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Votes Cast</td><td style=\"padding:8px;border:1px solid #ddd;\">{{votes_count}}</td></tr>\n</table>\n<p>Your vote has been securely recorded. Results will be announced at the event.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{voter_name}},\n\nThank you! Your vote for {{nominee_name}} in {{category_name}} has been recorded.\n\nVotes cast: {{votes_count}}\nEvent: {{event_name}}\n\n{{organizer_name}}', '[\"voter_name\", \"nominee_name\", \"category_name\", \"votes_count\", \"event_name\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(14, 'dcba53d3-821a-4cbb-be59-709e86980cfb', 2, 'General Announcement', 'general-announcement-2', 'general', 'A reusable template for general event announcements.', '{{subject_line}}', '<h2>{{subject_line}}</h2>\n<p>Hi {{attendee_name}},</p>\n<p>{{message_body}}</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\n{{message_body}}\n\nRegards,\n{{organizer_name}}', '[\"attendee_name\", \"subject_line\", \"message_body\", \"organizer_name\", \"event_name\"]', NULL, 1, 0, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(15, '64ab8625-856b-4a6e-9ff0-79abe78e6a9a', 3, 'Ticket Purchase Confirmation', 'ticket-purchase-confirmation-3', 'ticketing', 'Sent automatically when a ticket purchase is completed.', 'Your ticket for {{event_name}} is confirmed!', '<h2>Your Ticket is Confirmed!</h2>\n<p>Hi {{attendee_name}},</p>\n<p>Great news — your ticket for <strong>{{event_name}}</strong> has been confirmed.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Ticket #</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{ticket_number}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Ticket Type</td><td style=\"padding:8px;border:1px solid #ddd;\">{{ticket_type}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Event Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Amount Paid</td><td style=\"padding:8px;border:1px solid #ddd;\">{{amount_paid}}</td></tr>\n</table>\n<p>Please bring this confirmation or your QR code to the event entrance.</p>\n<p>We look forward to seeing you at <strong>{{event_name}}</strong>!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nYour ticket for {{event_name}} has been confirmed.\n\nTicket #: {{ticket_number}}\nDate: {{event_date}}\nVenue: {{event_venue}}\n\nPlease bring this confirmation or your QR code to the event.\n\nSee you there!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_venue\", \"ticket_number\", \"ticket_type\", \"amount_paid\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(16, 'f69866b7-5906-4583-8bb8-2bd7fd864b45', 3, 'Event Registration Confirmation', 'event-registration-confirmation-3', 'registration', 'Sent when a registration is approved or submitted.', 'Registration confirmed — {{event_name}}', '<h2>Registration Confirmed</h2>\n<p>Hi {{attendee_name}},</p>\n<p>Your registration for <strong>{{event_name}}</strong> has been approved.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Event</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{event_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>We\'re excited to have you join us. Please check the event schedule closer to the date.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nYour registration for {{event_name}} has been confirmed.\n\nEvent Date: {{event_date}}\nVenue: {{event_venue}}\n\nWe look forward to seeing you!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(17, '446e9a04-790f-4c5f-b5fa-05225fd074c8', 3, 'Payment Receipt', 'payment-receipt-3', 'financial', 'Sent when a payment is successfully processed.', 'Payment receipt — {{event_name}}', '<h2>Payment Receipt</h2>\n<p>Hi {{attendee_name}},</p>\n<p>We have successfully received your payment for <strong>{{event_name}}</strong>.</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Amount</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{amount}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Transaction ID</td><td style=\"padding:8px;border:1px solid #ddd;\">{{transaction_id}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Payment Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{payment_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Method</td><td style=\"padding:8px;border:1px solid #ddd;\">{{payment_method}}</td></tr>\n</table>\n<p>Please keep this receipt for your records.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nWe have received your payment of {{amount}} for {{event_name}}.\n\nTransaction ID: {{transaction_id}}\nDate: {{payment_date}}\nMethod: {{payment_method}}\n\nThank you!\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"amount\", \"transaction_id\", \"payment_date\", \"payment_method\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(18, '9c905b00-b46f-4eb6-a34c-5d0acca86991', 3, 'Event Reminder — 24 Hours', 'event-reminder-24-hours-3', 'reminder', 'Automatically sent 24 hours before the event starts.', 'Reminder: {{event_name}} is tomorrow!', '<h2>Event Reminder</h2>\n<p>Hi {{attendee_name}},</p>\n<p>This is a friendly reminder that <strong>{{event_name}}</strong> starts in <strong>24 hours</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Time</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_time}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>Don\'t forget to bring your ticket or QR code. See you soon!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\nJust a reminder that {{event_name}} starts tomorrow at {{event_time}}.\n\nVenue: {{event_venue}}\n\nDon\'t forget to bring your ticket!\n\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_date\", \"event_time\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(19, '6887c274-f049-47e9-a8d5-135b2d5c4516', 3, 'Event Reminder — 1 Hour', 'event-reminder-1-hour-3', 'reminder', 'Automatically sent 1 hour before the event starts.', '{{event_name}} starts in 1 hour!', '<h2>Event Reminder</h2>\n<p>Hi {{attendee_name}},</p>\n<p>This is a friendly reminder that <strong>{{event_name}}</strong> starts in <strong>1 hour</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Date</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_date}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Time</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_time}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Venue</td><td style=\"padding:8px;border:1px solid #ddd;\">{{event_venue}}</td></tr>\n</table>\n<p>Don\'t forget to bring your ticket or QR code. See you soon!</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\n{{event_name}} starts in just 1 hour! Head to {{event_venue}} now.\n\n{{organizer_name}}', '[\"attendee_name\", \"event_name\", \"event_time\", \"event_venue\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(20, '0e8614d3-b216-48a9-8fff-56dcf41207f4', 3, 'Voting Confirmation', 'voting-confirmation-3', 'voting', 'Sent when a vote is successfully cast.', 'Your vote has been counted — {{event_name}}', '<h2>Your Vote Has Been Counted!</h2>\n<p>Hi {{voter_name}},</p>\n<p>Thank you for participating in <strong>{{event_name}}</strong>!</p>\n<table style=\"border-collapse:collapse;width:100%;margin:16px 0;\">\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Voted For</td><td style=\"padding:8px;border:1px solid #ddd;font-weight:bold;\">{{nominee_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Category</td><td style=\"padding:8px;border:1px solid #ddd;\">{{category_name}}</td></tr>\n    <tr><td style=\"padding:8px;border:1px solid #ddd;color:#666;\">Votes Cast</td><td style=\"padding:8px;border:1px solid #ddd;\">{{votes_count}}</td></tr>\n</table>\n<p>Your vote has been securely recorded. Results will be announced at the event.</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{voter_name}},\n\nThank you! Your vote for {{nominee_name}} in {{category_name}} has been recorded.\n\nVotes cast: {{votes_count}}\nEvent: {{event_name}}\n\n{{organizer_name}}', '[\"voter_name\", \"nominee_name\", \"category_name\", \"votes_count\", \"event_name\", \"organizer_name\"]', NULL, 1, 1, '2026-03-04 09:17:02', '2026-03-04 09:17:02'),
(21, '85b9c4cf-7cb6-4b6c-bfb6-24744f57ad1a', 3, 'General Announcement', 'general-announcement-3', 'general', 'A reusable template for general event announcements.', '{{subject_line}}', '<h2>{{subject_line}}</h2>\n<p>Hi {{attendee_name}},</p>\n<p>{{message_body}}</p>\n<p>Regards,<br><strong>{{organizer_name}}</strong></p>', 'Hi {{attendee_name}},\n\n{{message_body}}\n\nRegards,\n{{organizer_name}}', '[\"attendee_name\", \"subject_line\", \"message_body\", \"organizer_name\", \"event_name\"]', NULL, 1, 0, '2026-03-04 09:17:02', '2026-03-04 09:17:02');

-- --------------------------------------------------------

--
-- Table structure for table `events`
--

CREATE TABLE `events` (
  `id` bigint UNSIGNED NOT NULL,
  `uuid` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `client_id` bigint UNSIGNED NOT NULL,
  `venue_id` bigint UNSIGNED DEFAULT NULL,
  `organizer_id` bigint UNSIGNED DEFAULT NULL,
  `event_category_id` bigint UNSIGNED DEFAULT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tagline` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `short_description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `type` enum('awards','pageant','conference','tournament','concert','other') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'awards',
  `event_format` enum('in-person','virtual','hybrid') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'in-person',
  `banner_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `thumbnail_image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `logo` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `venue_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `venue_address` text COLLATE utf8mb4_unicode_ci,
  `venue_city` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `venue_country` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_virtual` tinyint(1) NOT NULL DEFAULT '0',
  `virtual_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `start_date` date NOT NULL,
  `end_date` date DEFAULT NULL,
  `start_time` time DEFAULT NULL,
  `end_time` time DEFAULT NULL,
  `timezone` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Africa/Nairobi',
  `registration_opens_at` timestamp NULL DEFAULT NULL,
  `registration_closes_at` timestamp NULL DEFAULT NULL,
  `voting_opens_at` timestamp NULL DEFAULT NULL,
  `voting_closes_at` timestamp NULL DEFAULT NULL,
  `status` enum('draft','published','ongoing','completed','cancelled','postponed','pending_review','rejected') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft',
  `voting_commission_rate` decimal(5,2) DEFAULT NULL,
  `ticketing_commission_rate` decimal(5,2) DEFAULT NULL,
  `total_voting_revenue` decimal(15,2) NOT NULL DEFAULT '0.00',
  `total_ticketing_revenue` decimal(15,2) NOT NULL DEFAULT '0.00',
  `platform_commission_total` decimal(15,2) NOT NULL DEFAULT '0.00',
  `client_revenue_total` decimal(15,2) NOT NULL DEFAULT '0.00',
  `visibility` enum('public','private','unlisted') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'public',
  `is_featured` tinyint(1) NOT NULL DEFAULT '0',
  `has_voting` tinyint(1) NOT NULL DEFAULT '0',
  `has_ticketing` tinyint(1) NOT NULL DEFAULT '0',
  `has_registration` tinyint(1) NOT NULL DEFAULT '0',
  `max_attendees` int UNSIGNED DEFAULT NULL,
  `current_attendees` int UNSIGNED NOT NULL DEFAULT '0',
  `terms_conditions` text COLLATE utf8mb4_unicode_ci,
  `meta` json DEFAULT NULL,
  `seo_title` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `seo_description` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `seo_keywords` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `views_count` bigint UNSIGNED NOT NULL DEFAULT '0',
  `shares_count` int UNSIGNED NOT NULL DEFAULT '0',
  `created_by` bigint UNSIGNED DEFAULT NULL,
  `published_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `rejection_reason` text COLLATE utf8mb4_unicode_ci
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Dumping data for table `events`
--

INSERT INTO `events` (`id`, `uuid`, `client_id`, `venue_id`, `organizer_id`, `event_category_id`, `name`, `slug`, `tagline`, `description`, `short_description`, `type`, `event_format`, `banner_image`, `thumbnail_image`, `logo`, `venue_name`, `venue_address`, `venue_city`, `venue_country`, `is_virtual`, `virtual_url`, `start_date`, `end_date`, `start_time`, `end_time`, `timezone`, `registration_opens_at`, `registration_closes_at`, `voting_opens_at`, `voting_closes_at`, `status`, `voting_commission_rate`, `ticketing_commission_rate`, `total_voting_revenue`, `total_ticketing_revenue`, `platform_commission_total`, `client_revenue_total`, `visibility`, `is_featured`, `has_voting`, `has_ticketing`, `has_registration`, `max_attendees`, `current_attendees`, `terms_conditions`, `meta`, `seo_title`, `seo_description`, `seo_keywords`, `views_count`, `shares_count`, `created_by`, `published_at`, `created_at`, `updated_at`, `deleted_at`, `rejection_reason`) VALUES
(55, '40760722-e3b5-4590-9267-74aa7de346a1', 4, 8, NULL, NULL, 'IKWA 2026 Awards Gala', 'ikwa-2026', 'Celebrating Women Who Shape Kenya\'s Future', 'The Independent Kenya Women Awards (IKWA) 2026 brings together Kenya\'s most outstanding women in leadership, business, and social impact for an unforgettable evening of recognition and celebration.\n\nJoin us as we honour the Top 100 Women in Leadership, Top 100 Women in Business & Brands, 100 Women of Influence in Kenya, and crown the Miss Independent Kenya 2026.\n\nThe evening features a gala dinner, live entertainment, and an inspiring programme celebrating Kenyan women who are shaping the nation\'s future.\n\nTheme: Celebrating Women Who Shape Kenya\'s Future', 'Annual gala celebrating Kenya\'s top women in leadership, business, influence and culture. Join us for an evening of awards, inspiration and celebration.', 'awards', 'in-person', 'events/55/banner_ikwa-2026_AOfXDJ0e.webp', 'events/55/thumbnail_ikwa-2026_tH0P1raO.webp', 'events/55/logo_ikwa-2026_0f3Fe5pS.jpeg', 'Radisson Blu Hotel Nairobi Upper Hill', 'Upper Hill, Hospital Road', 'Nairobi', 'Kenya', 0, NULL, '2026-05-30', '2026-05-30', '18:00:00', '23:00:00', 'Africa/Nairobi', NULL, NULL, '2026-03-09 21:00:00', '2026-04-30 20:59:59', 'published', 18.00, 4.00, 0.00, 0.00, 0.00, 0.00, 'public', 1, 1, 1, 0, NULL, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, NULL, '2026-03-06 10:00:42', '2026-03-06 07:32:20', '2026-03-15 08:08:16', NULL, NULL),
(60, 'f21e70bf-a186-4c0f-88cf-1045fa2d1b53', 1, NULL, NULL, NULL, 'Tuqio Entrepreneurship Awards 2026', 'tuqio-entrepreneurship-2026', 'Celebrating Kenya\'s most innovative entrepreneurs', 'The Tuqio Entrepreneurship Awards 2026 recognises outstanding entrepreneurs across Kenya. This event is currently in the nomination phase — submit your nominee today and help us identify the next generation of business leaders.', 'Nominate Kenya\'s top entrepreneurs for the 2026 awards.', 'awards', 'in-person', NULL, NULL, NULL, 'Radisson Blu Hotel', 'Upper Hill', 'Nairobi', 'Kenya', 0, NULL, '2026-05-10', '2026-05-10', '18:00:00', '22:00:00', 'Africa/Nairobi', NULL, NULL, NULL, NULL, 'published', NULL, NULL, 0.00, 0.00, 0.00, 0.00, 'public', 1, 0, 0, 0, NULL, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, NULL, NULL, '2026-03-11 07:06:41', '2026-03-11 07:06:41', NULL, NULL),
(61, '350542b6-008e-4a14-bb0a-51dcac4b9ee4', 1, NULL, NULL, NULL, 'Tuqio Awards Gala 2026', 'tuqio-gala-2026', 'An evening celebrating excellence, impact, and ambition', 'The Tuqio Awards Gala 2026 is a prestigious ceremony honouring Kenya\'s top performers in leadership, business, innovation, and youth development. Voting is now open — cast your votes for your favourite candidates and secure your tickets to join us on the night.', 'Kenya\'s premier awards gala — voting open now.', 'awards', 'in-person', NULL, NULL, NULL, 'Safari Park Hotel', 'Thika Road', 'Nairobi', 'Kenya', 0, NULL, '2026-04-10', '2026-04-10', '18:00:00', '23:00:00', 'Africa/Nairobi', NULL, NULL, '2026-03-11 06:06:44', '2026-04-05 07:06:44', 'published', 10.00, NULL, 0.00, 0.00, 0.00, 0.00, 'public', 1, 1, 1, 0, NULL, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, NULL, NULL, '2026-03-11 07:06:44', '2026-03-11 07:06:44', NULL, NULL),
(62, '9e7dd868-06d9-462d-9cdd-58d7971d2193', 1, NULL, NULL, NULL, 'Tuqio Live Voting Demo 2026', 'tuqio-live-demo-2026', 'Live voting demo — see real-time vote counts in action', 'The Tuqio Live Voting Demo 2026 showcases the full voting experience. Voting is live across 3 categories — cast your votes, buy vote bundles, and watch the leaderboard update in real time. This is a demonstration event for the Tuqio platform.', 'Live voting demo — cast your votes and see the leaderboard update.', 'awards', 'in-person', NULL, NULL, NULL, 'Tuqio Virtual Arena', NULL, 'Nairobi', 'Kenya', 1, NULL, '2026-03-25', '2026-03-25', '19:00:00', '22:00:00', 'Africa/Nairobi', NULL, NULL, '2026-03-08 07:06:47', '2026-03-22 07:06:47', 'published', 10.00, NULL, 0.00, 0.00, 0.00, 0.00, 'public', 1, 1, 0, 0, NULL, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, NULL, NULL, '2026-03-11 07:06:47', '2026-03-11 07:06:47', NULL, NULL),
(66, 'c814fd12-888d-49a4-a4c9-56749fd0327f', 6, NULL, NULL, 1, 'MEMA 2026 — Myogenic Excellence Music Awards Gala', 'mema-gala-2026', 'Honouring Africa\'s Voices and Sounds.', 'The Vision\r\n\r\nThe Myogenic Excellence Music Awards — MEMA — was born from a simple but powerful conviction: African gospel music is world-class, and its creators deserve a world-class platform to be recognised. Kenya\'s gospel music scene has produced artists, producers, directors, and photographers whose work has touched millions of lives across the continent and beyond. MEMA 2026 is the inaugural celebration of that excellence.\r\n\r\nWhat to Expect on the Night\r\n\r\nThe MEMA Gala 2026 is a full black-tie gala evening held at the Radisson Blu Hotel & Convention Centre, Nairobi, on September 16, 2026. Doors open at 4:30 PM with a red carpet reception and networking cocktails. The main ceremony begins at 7:00 PM and features live gospel performances by nominated artists, a sit-down gala dinner, and the presentation of all MEMA awards across three awards blocks. The evening concludes with an after-gala celebration and group photography with award winners.\r\n\r\nHow Nominations and Voting Work\r\n\r\nAnyone can nominate a gospel artist, producer, director, or photographer they believe deserves recognition. Nominations are submitted online, reviewed by the MEMA team, and shortlisted nominees are published for public voting. The nomination window runs from April 16 to July 15, 2026. Public voting opens August 1 and closes September 14, 2026 — giving the gospel music community the power to crown their champions before the big night.\r\n\r\nTickets\r\n\r\nTickets are available in multiple tiers to suit individual guests, couples, organisations, and corporate tables — from Early Bird Regular Seats (KES 1,000) to VVIP Tables for 10 (KES 50,000). All tickets include a gala dinner and event programme. VIP and VVIP tickets include priority seating, VIP lounge access, and meet & greet opportunities with award winners.\r\n\r\nBe Part of the Story\r\n\r\nMEMA 2026 is more than an event — it is a movement. Whether you are nominating an artist you believe in, casting your vote, attending the gala, or sponsoring a category, you are part of something historic. This is the beginning of a new chapter for gospel music recognition in Africa.', 'The inaugural Myogenic Excellence Music Awards — celebrating outstanding talent across gospel music, production, videography, and photography in Africa.', 'awards', 'in-person', 'events/66/banner_mema-gala-2026_p7kmkf6u.jpeg', 'events/66/thumbnail_mema-gala-2026_fdsDite9.jpeg', 'events/66/logo_mema-gala-2026_Dt8BzBal.png', 'Radisson Blu Hotel & Convention Centre, Nairobi', 'Upper Hill Road, Upper Hill', 'Nairobi', 'Kenya', 0, NULL, '2026-09-16', '2026-09-16', '16:30:00', '23:59:00', 'Africa/Nairobi', NULL, NULL, '2025-12-31 21:00:00', '2026-12-31 20:59:59', 'published', 2.00, 5.00, 0.00, 0.00, 0.00, 0.00, 'public', 1, 1, 1, 1, NULL, 0, NULL, NULL, NULL, NULL, NULL, 0, 0, NULL, '2026-03-26 09:20:45', '2026-03-26 09:20:45', '2026-03-26 12:09:51', NULL, NULL);

