INSERT INTO `event_faqs` (`id`, `event_id`, `question`, `answer`, `sort_order`, `is_active`, `created_at`, `updated_at`) VALUES
(102, 66, 'How do I vote for my favourite nominee?', 'Visit the MEMA Gala 2026 event page on tuqiohub.africa, choose your nominee, select a vote bundle, and complete payment via M-Pesa or card. Your votes are credited instantly.', 1, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(103, 66, 'How much does one vote cost?', 'One vote costs KES 100. You can buy vote bundles for discounts — e.g. 50 votes for KES 4,000 (save 20%) or 100 votes for KES 7,000 (save 30%).', 2, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(104, 66, 'Can I buy votes for different nominees?', 'Yes! You can purchase vote bundles and distribute them across different nominees and categories as you wish.', 3, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(105, 66, 'When does voting open and close?', 'Public voting opens on August 1, 2026 and closes on September 14, 2026 at 11:59 PM (EAT). No votes are accepted after the deadline.', 4, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(106, 66, 'How do I nominate someone?', 'Visit tuqiohub.africa/nominate, select the MEMA Gala 2026 event, choose a category, and fill in the nomination form. Nominations are open from April 16 to July 15, 2026.', 5, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(107, 66, 'Can I nominate myself?', 'Yes, self-nominations are accepted! Fill out the nomination form with your own details and explain why you deserve the award.', 6, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(108, 66, 'When does the nomination window open and close?', 'Public nominations open on April 16, 2026 and close on July 15, 2026 at 11:59 PM. After this, the MEMA team reviews all nominations and promotes shortlisted nominees to the voting phase.', 7, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(109, 66, 'Which categories are open for public nomination?', 'Eight out of nine categories are open for public nomination: Female Artist, Male Artist, Emerging Gospel Artist, Gospel Song, Gospel Video, Audio Producer, Video Director, and Photography of the Year. Gospel Collaboration of the Year is nominated directly by the MEMA team.', 8, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(110, 66, 'How do I buy event tickets?', 'Visit the MEMA Gala 2026 event page, click \"Get Tickets\", choose your ticket type (Early Bird, Regular, VIP, or VVIP), and complete payment. You will receive your e-ticket via email and SMS.', 9, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(111, 66, 'Are there early bird tickets?', 'Yes! Early Bird Regular Seats (KES 1,000) and Early Bird VIP Seats (KES 2,500) are available from April 16 to June 30, 2026 at a significant discount. Limited quantities — book early!', 10, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(112, 66, 'Where is the event held?', 'MEMA Gala 2026 will be held in Nairobi, Kenya on September 16, 2026. The exact venue will be announced soon. Stay tuned on our social media channels.', 11, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45'),
(113, 66, 'Can I get a refund on my ticket?', 'Tickets are non-refundable once purchased. However, ticket transfers are allowed — contact us at info@tuqiohub.africa with your booking reference to arrange a transfer.', 12, 1, '2026-03-26 09:20:45', '2026-03-26 09:20:45');

