(56, 66, NULL, 'Dr. Ezekiel Mutua', NULL, NULL, 'CEO, Kenya Film Classification Board', 'Kenya Film Classification Board', 'Dr. Ezekiel Mutua (PhD) is a media strategist, motivational speaker, and CEO of the Kenya Film Classification Board. A passionate advocate for African values in media and entertainment.', 'speakers/photos/6K05kzjLNJkcbnruVwLdQR5qFfHYWipQwjcwCCXw.webp', NULL, NULL, 'keynote', '[]', 1, 1, 1, '2026-03-26 09:20:45', '2026-03-26 11:15:23'),
(57, 66, NULL, 'Eunice Njeri', NULL, NULL, 'Award-Winning Gospel Artist & Worship Leader', 'Independent', 'Eunice Njeri is one of Kenya\'s most celebrated gospel artists, known for chart-topping worship songs and her passionate ministry across Africa.', 'speakers/photos/LkYFoXUCiz5Xa71gvj3nqAV22fbAUUJBvPCgUM1p.webp', NULL, NULL, 'speaker', '[]', 2, 1, 1, '2026-03-26 09:20:45', '2026-03-26 11:15:10'),
(58, 66, NULL, 'Aaron Rimbui', NULL, NULL, 'Music Producer & Composer', 'Rimbui Studios', 'Aaron Rimbui is a multi-award-winning music producer and composer who has shaped the sound of Kenyan gospel and contemporary music for over two decades.', 'speakers/photos/q4uwKuTIVkgeOZbWAbdesCrl53dhEiEWNxq1e9b4.webp', NULL, NULL, 'speaker', '[]', 3, 0, 1, '2026-03-26 09:20:45', '2026-03-26 11:15:00'),
(59, 66, NULL, 'Rev. Dr. Josephine Naphtali', NULL, NULL, 'Minister of Music & Founder, Music Ministry Africa', 'Music Ministry Africa', 'Rev. Dr. Josephine Naphtali is a minister, gospel musician, and founder of Music Ministry Africa — dedicated to equipping African gospel artists for impact.', 'speakers/photos/78ybwLX6dzBXk5YC9eNke9rIvk4ihDoDAIFWUtf9.webp', NULL, NULL, 'panelist', '[]', 4, 0, 1, '2026-03-26 09:20:45', '2026-03-26 11:14:33'),
(60, 66, NULL, 'Jimmy Gait', NULL, NULL, 'Gospel Artist & MC', 'Independent', 'Jimmy Gait is a beloved Kenyan gospel artist and entertainer known for his energetic performances and ability to unite audiences through music and laughter.', 'speakers/photos/GMOlOO0kmbBsHsXScaXM4VyMA5CHZLxx0yOIrG74.webp', NULL, NULL, 'moderator', '[]', 5, 0, 1, '2026-03-26 09:20:45', '2026-03-26 11:14:48');

