-- --------------------------------------------------------

--
-- Table structure for table `nominee_categories`
--

CREATE TABLE `nominee_categories` (
  `id` bigint UNSIGNED NOT NULL,
  `uuid` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `event_id` bigint UNSIGNED NOT NULL,
  `voting_category_id` bigint UNSIGNED DEFAULT NULL,
  `name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `slug` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text COLLATE utf8mb4_unicode_ci,
  `image` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `sort_order` int NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `voting_enabled` tinyint(1) NOT NULL DEFAULT '1',
  `nomination_status` enum('collecting','reviewing','promoted','voting') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'collecting',
  `nomination_starts_at` timestamp NULL DEFAULT NULL,
  `nomination_ends_at` timestamp NULL DEFAULT NULL,
  `nomination_type` enum('admin_only','public_nomination','application_form') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'admin_only',
  `nomination_questions` json DEFAULT NULL,
  `selection_method` enum('manual','automatic') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'manual',
  `top_nominees_count` int NOT NULL DEFAULT '5',
  `selection_criteria` enum('votes_count','votes_amount','votes_percentage') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'votes_count',
  `minimum_votes` int NOT NULL DEFAULT '0',
  `max_winners` tinyint UNSIGNED NOT NULL DEFAULT '1',
  `display_type` enum('grid','list','carousel') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'grid',
  `nominees_per_row` tinyint UNSIGNED NOT NULL DEFAULT '3',
  `meta` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

