INSERT INTO `pages` (`id`, `uuid`, `client_id`, `event_id`, `parent_id`, `author_id`, `title`, `slug`, `content`, `template`, `featured_image`, `status`, `published_at`, `is_homepage`, `is_in_menu`, `menu_order`, `seo_title`, `seo_description`, `seo_keywords`, `og_image`, `canonical_url`, `created_at`, `updated_at`, `deleted_at`) VALUES
(1, 'a4b5475c-5248-4216-bffd-49c49150e3b5', 1, NULL, NULL, 2, 'Home', 'home', '<h1>Welcome to Tuqio Hub Demo</h1>\n<p>Your premier event management and ticketing platform. We help organizations create, manage, and promote exceptional events that bring people together.</p>\n<h2>Why Choose Us?</h2>\n<ul>\n<li>Easy-to-use event management tools</li>\n<li>Secure ticketing and payment processing</li>\n<li>Real-time voting and engagement features</li>\n<li>Comprehensive analytics and reporting</li>\n<li>24/7 customer support</li>\n</ul>\n<p>Get started today and transform the way you manage events!</p>', 'full-width', NULL, 'published', '2026-02-01 17:44:08', 1, 1, 1, 'Tuqio Hub Demo - Event Management Platform', 'Welcome to Tuqio Hub Demo, your premier event management and ticketing platform.', 'events, ticketing, event management, tuqio hub demo', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(2, '453e9b29-c6a7-4309-a2fb-0758efd7f8fa', 1, NULL, NULL, 2, 'About Us', 'about', '<h1>About Tuqio Hub Demo</h1>\n<p>We are passionate about creating technology that brings people together through exceptional event experiences.</p>\n<h2>Our Mission</h2>\n<p>To empower event organizers with innovative tools that simplify management, enhance attendee experiences, and drive engagement.</p>\n<h2>Our Vision</h2>\n<p>To be the leading event management platform that transforms how organizations connect with their audiences.</p>\n<h2>What We Offer</h2>\n<p>From ticketing to voting, from registration to analytics, we provide comprehensive solutions for all your event needs.</p>', 'sidebar-right', NULL, 'published', '2026-02-06 17:44:08', 0, 1, 2, 'About Tuqio Hub Demo', 'Learn more about Tuqio Hub Demo and our mission to transform event management.', 'about, company, mission, tuqio hub demo', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(3, '1f7aebc7-c938-4a0b-9728-c129b631b5ac', 1, NULL, NULL, 2, 'Contact Us', 'contact', '<h1>Contact Us</h1>\n<p>We\'d love to hear from you! Get in touch with our team for support, partnership inquiries, or general questions.</p>\n<h2>Get in Touch</h2>\n<p><strong>Email:</strong> support@tuqio-hub-demo.com<br>\n<strong>Phone:</strong> +254 700 000 000<br>\n<strong>Office Hours:</strong> Monday - Friday, 9:00 AM - 6:00 PM EAT</p>\n<h2>Support</h2>\n<p>For technical support, please visit our Help Center or submit a support ticket through your dashboard.</p>', 'sidebar-right', NULL, 'published', '2026-02-06 17:44:08', 0, 1, 3, 'Contact Tuqio Hub Demo', 'Get in touch with the Tuqio Hub Demo team. We\'re here to help!', 'contact, support, help, tuqio hub demo', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(4, 'f86b3092-56fa-4ed7-951d-118a72771ac8', 1, NULL, NULL, 2, 'Terms of Service', 'terms', '<h1>Terms of Service</h1>\n<p><strong>Last Updated:</strong> March 03, 2026</p>\n<h2>1. Acceptance of Terms</h2>\n<p>By accessing and using Tuqio Hub Demo, you accept and agree to be bound by the terms and provision of this agreement.</p>\n<h2>2. Use License</h2>\n<p>Permission is granted to temporarily use Tuqio Hub Demo for personal, non-commercial transitory viewing only.</p>\n<h2>3. User Account</h2>\n<p>You are responsible for maintaining the confidentiality of your account and password and for restricting access to your account.</p>\n<h2>4. Limitation of Liability</h2>\n<p>In no event shall Tuqio Hub Demo be liable for any damages arising out of the use or inability to use our services.</p>', 'default', NULL, 'published', '2026-01-02 17:44:08', 0, 0, 0, 'Terms of Service - Tuqio Hub Demo', 'Read our terms of service and user agreement.', 'terms, legal, agreement', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(5, 'af94b8ce-a96f-4515-b7d5-0be1355200cd', 1, NULL, NULL, 2, 'Privacy Policy', 'privacy', '<h1>Privacy Policy</h1>\n<p><strong>Last Updated:</strong> March 03, 2026</p>\n<h2>1. Information We Collect</h2>\n<p>We collect information you provide directly to us, such as when you create an account, purchase tickets, or contact us for support.</p>\n<h2>2. How We Use Your Information</h2>\n<p>We use the information we collect to provide, maintain, and improve our services, process transactions, and communicate with you.</p>\n<h2>3. Information Sharing</h2>\n<p>We do not sell, trade, or otherwise transfer your personally identifiable information to outside parties without your consent.</p>\n<h2>4. Data Security</h2>\n<p>We implement appropriate security measures to protect your personal information from unauthorized access.</p>', 'default', NULL, 'published', '2026-01-02 17:44:08', 0, 0, 0, 'Privacy Policy - Tuqio Hub Demo', 'Learn how we protect your privacy and handle your data.', 'privacy, data protection, gdpr', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(6, 'a87be309-0f73-4916-979b-5e9011424add', 1, NULL, NULL, 2, 'Frequently Asked Questions', 'faq', '<h1>Frequently Asked Questions</h1>\n<h2>How do I create an event?</h2>\n<p>Sign in to your account, navigate to the dashboard, and click \'Create Event\'. Follow the step-by-step wizard to set up your event.</p>\n<h2>How does ticketing work?</h2>\n<p>You can create multiple ticket types with different pricing. Attendees purchase tickets through our secure payment system, and receive digital tickets via email.</p>\n<h2>Can I customize my event page?</h2>\n<p>Yes! You can customize colors, add images, write descriptions, and include custom fields in your registration forms.</p>\n<h2>What payment methods do you support?</h2>\n<p>We support M-Pesa, credit/debit cards via Paystack, bank transfers, and cash payments.</p>\n<h2>How do I get support?</h2>\n<p>Contact our support team via email, live chat, or submit a support ticket through your dashboard.</p>', 'sidebar-left', NULL, 'published', '2026-02-11 17:44:08', 0, 1, 4, 'FAQ - Tuqio Hub Demo', 'Find answers to commonly asked questions about our platform.', 'faq, help, questions, support', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(7, 'adfbfe19-d87a-4cd7-b6bb-1fcae517434e', 1, NULL, NULL, 2, 'Services', 'services', '<h1>Our Services</h1>\n<p>Tuqio Hub Demo provides comprehensive event management solutions designed to make your events successful.</p>\n<h2>Event Management</h2>\n<p>Create, manage, and promote events with our intuitive platform. Handle registrations, track attendance, and engage your audience.</p>\n<h2>Ticketing Solutions</h2>\n<p>Secure, flexible ticketing with multiple pricing tiers, early bird discounts, and group booking options.</p>\n<h2>Voting & Polls</h2>\n<p>Engage your audience with real-time voting, polls, and interactive features that drive participation.</p>\n<h2>Analytics & Reporting</h2>\n<p>Gain insights into attendee behavior, ticket sales, and engagement metrics with our comprehensive analytics tools.</p>', 'default', NULL, 'published', '2026-02-16 17:44:08', 0, 1, 5, 'Our Services - Tuqio Hub Demo', 'Explore our comprehensive event management services.', 'services, event management, ticketing, voting', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(8, 'aee98532-3f0f-4392-b87c-134981c327ea', 1, NULL, 7, 2, 'Event Management', 'event-management', '<h1>Event Management Services</h1>\n<p>Our event management platform streamlines every aspect of organizing successful events.</p>\n<h2>Features</h2>\n<ul>\n<li>Customizable event pages</li>\n<li>Multi-tier ticketing</li>\n<li>Automated email communications</li>\n<li>Check-in and attendance tracking</li>\n<li>Real-time analytics and reporting</li>\n<li>Integration with payment gateways</li>\n</ul>\n<h2>Benefits</h2>\n<p>Save time, reduce costs, and create better experiences for your attendees with our all-in-one platform.</p>', 'default', NULL, 'published', '2026-02-16 17:44:08', 0, 0, 0, 'Event Management Services - Tuqio Hub Demo', 'Professional event management solutions for organizations of all sizes.', 'event management, planning, organization', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
(9, 'c160ea55-9911-4826-b156-bdf2643e31af', 2, NULL, NULL, 4, 'Home', 'home', '<h1>Welcome to Tech Events Kenya</h1>\n<p>Your premier event management and ticketing platform. We help organizations create, manage, and promote exceptional events that bring people together.</p>\n<h2>Why Choose Us?</h2>\n<ul>\n<li>Easy-to-use event management tools</li>\n<li>Secure ticketing and payment processing</li>\n<li>Real-time voting and engagement features</li>\n<li>Comprehensive analytics and reporting</li>\n<li>24/7 customer support</li>\n</ul>\n<p>Get started today and transform the way you manage events!</p>', 'full-width', NULL, 'published', '2026-02-01 17:44:08', 1, 1, 1, 'Tech Events Kenya - Event Management Platform', 'Welcome to Tech Events Kenya, your premier event management and ticketing platform.', 'events, ticketing, event management, tech events kenya', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
