(11, 'be13027f-8b37-4384-9c1f-eb60eaf095fd', 2, NULL, NULL, 4, 'Contact Us', 'contact', '<h1>Contact Us</h1>\n<p>We\'d love to hear from you! Get in touch with our team for support, partnership inquiries, or general questions.</p>\n<h2>Get in Touch</h2>\n<p><strong>Email:</strong> support@tech-events-kenya.com<br>\n<strong>Phone:</strong> +254 700 000 000<br>\n<strong>Office Hours:</strong> Monday - Friday, 9:00 AM - 6:00 PM EAT</p>\n<h2>Support</h2>\n<p>For technical support, please visit our Help Center or submit a support ticket through your dashboard.</p>', 'sidebar-right', NULL, 'published', '2026-02-06 17:44:08', 0, 1, 3, 'Contact Tech Events Kenya', 'Get in touch with the Tech Events Kenya team. We\'re here to help!', 'contact, support, help, tech events kenya', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL),
