(16, '975df1f6-5995-46e4-bed9-b14b7f867603', 2, NULL, 15, 4, 'Event Management', 'event-management', '<h1>Event Management Services</h1>\n<p>Our event management platform streamlines every aspect of organizing successful events.</p>\n<h2>Features</h2>\n<ul>\n<li>Customizable event pages</li>\n<li>Multi-tier ticketing</li>\n<li>Automated email communications</li>\n<li>Check-in and attendance tracking</li>\n<li>Real-time analytics and reporting</li>\n<li>Integration with payment gateways</li>\n</ul>\n<h2>Benefits</h2>\n<p>Save time, reduce costs, and create better experiences for your attendees with our all-in-one platform.</p>', 'default', NULL, 'published', '2026-02-16 17:44:08', 0, 0, 0, 'Event Management Services - Tech Events Kenya', 'Professional event management solutions for organizations of all sizes.', 'event management, planning, organization', NULL, NULL, '2026-03-03 17:44:08', '2026-03-03 17:44:08', NULL);

