(11, '7423d28d-1314-41bf-8a03-1e5c47961957', 2, NULL, 7, 4, 'IKWA Awards 2026: Voting Now Open', 'ikwa-awards-2026-voting-now-open', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', '<p>The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memorable experiences requires a combination of strategic planning, audience engagement, and seamless execution.</p><p>In today\'s digital age, event organizers have access to powerful tools that streamline ticketing, enhance attendee experiences, and provide valuable insights through data analytics. These platforms enable organizers to focus on what matters most: creating exceptional events that resonate with their audience.</p><p>Successful events are built on strong foundations of communication, collaboration, and creativity. By leveraging modern event management solutions, organizers can reduce administrative overhead while increasing attendee satisfaction and engagement.</p>', NULL, NULL, 'published', '2026-02-28 17:44:05', 1, 0, 1, 0, 0, 0, 5, 'IKWA Awards 2026: Voting Now Open - Tech Events Kenya', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', 'events, ticketing, voting, awards', 'media/posts/post-image-7.jpg', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', NULL, '2026-03-03 17:44:05', '2026-03-03 18:10:35', NULL),
(12, 'ebb58c00-189e-4aa9-8b88-22a751eb33df', 2, NULL, 6, 4, 'How to Create Memorable Event Experiences', 'how-to-create-memorable-event-experiences', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', '<p>The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memorable experiences requires a combination of strategic planning, audience engagement, and seamless execution.</p><p>In today\'s digital age, event organizers have access to powerful tools that streamline ticketing, enhance attendee experiences, and provide valuable insights through data analytics. These platforms enable organizers to focus on what matters most: creating exceptional events that resonate with their audience.</p><p>Successful events are built on strong foundations of communication, collaboration, and creativity. By leveraging modern event management solutions, organizers can reduce administrative overhead while increasing attendee satisfaction and engagement.</p>', 'posts/featured-images/USRuIafSjjrBkXfUsAyvvNlK10mmkUzexdyb1UHn.webp', 'How to Create Memorable Event Experiences', 'published', '2026-02-24 17:44:00', 0, 0, 1, 0, 0, 0, 1, 'How to Create Memorable Event Experiences - Tech Events Kenya', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', 'events, ticketing, voting, awards', 'media/posts/post-image-5.jpg', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', NULL, '2026-03-03 17:44:05', '2026-03-09 15:48:06', NULL),
(13, 'b418938e-eb1a-43c0-8b9a-91a7663ee002', 2, NULL, 9, 4, 'Top 10 Event Management Tips for 2026', 'top-10-event-management-tips-for-2026', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', '<p>The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memorable experiences requires a combination of strategic planning, audience engagement, and seamless execution.</p><p>In today\'s digital age, event organizers have access to powerful tools that streamline ticketing, enhance attendee experiences, and provide valuable insights through data analytics. These platforms enable organizers to focus on what matters most: creating exceptional events that resonate with their audience.</p><p>Successful events are built on strong foundations of communication, collaboration, and creativity. By leveraging modern event management solutions, organizers can reduce administrative overhead while increasing attendee satisfaction and engagement.</p><p>The future of events lies in hybrid experiences that blend physical and virtual elements, creating opportunities for broader participation and enhanced accessibility. This evolution opens new possibilities for event organizers to reach global audiences while maintaining the intimacy of in-person connections.</p><p>As the industry continues to grow, staying ahead of trends and adopting best practices becomes essential for success. Event organizers who embrace innovation and prioritize attendee experience will find themselves well-positioned to thrive in this dynamic landscape.</p>', 'posts/featured-images/HbfKzOGIuh7U8aZyu02MzZhC6LOq8GzHGccLJMmf.webp', 'Top 10 Event Management Tips for 2026', 'published', '2026-02-26 17:44:00', 0, 1, 1, 0, 0, 0, 1, 'Top 10 Event Management Tips for 2026 - Tech Events Kenya', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', 'events, ticketing, voting, awards', 'media/posts/post-image-4.jpg', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', NULL, '2026-03-03 17:44:05', '2026-03-09 15:48:38', NULL),
