(19, '953dc100-6589-42ef-81b2-425e1efec599', 2, NULL, 7, 4, 'Year in Review: 2026 Event Highlights', 'year-in-review-2026-event-highlights', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', '<p>The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memorable experiences requires a combination of strategic planning, audience engagement, and seamless execution.</p><p>In today\'s digital age, event organizers have access to powerful tools that streamline ticketing, enhance attendee experiences, and provide valuable insights through data analytics. These platforms enable organizers to focus on what matters most: creating exceptional events that resonate with their audience.</p><p>Successful events are built on strong foundations of communication, collaboration, and creativity. By leveraging modern event management solutions, organizers can reduce administrative overhead while increasing attendee satisfaction and engagement.</p><p>The future of events lies in hybrid experiences that blend physical and virtual elements, creating opportunities for broader participation and enhanced accessibility. This evolution opens new possibilities for event organizers to reach global audiences while maintaining the intimacy of in-person connections.</p><p>As the industry continues to grow, staying ahead of trends and adopting best practices becomes essential for success. Event organizers who embrace innovation and prioritize attendee experience will find themselves well-positioned to thrive in this dynamic landscape.</p>', 'media/posts/post-image-2.jpg', 'Year in Review: 2026 Event Highlights', 'scheduled', '2026-04-02 17:44:05', 0, 0, 1, 0, 0, 0, 3, 'Year in Review: 2026 Event Highlights - Tech Events Kenya', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', 'events, ticketing, voting, awards', 'media/posts/post-image-3.jpg', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', NULL, '2026-03-03 17:44:05', '2026-03-03 17:44:05', NULL),
(20, '4c7c479e-e5f0-43f6-ae0a-f5ed155daa87', 2, NULL, 9, 4, 'Guest Post: Success Stories from Event Organizers', 'guest-post-success-stories-from-event-organizers', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', '<p>The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memorable experiences requires a combination of strategic planning, audience engagement, and seamless execution.</p><p>In today\'s digital age, event organizers have access to powerful tools that streamline ticketing, enhance attendee experiences, and provide valuable insights through data analytics. These platforms enable organizers to focus on what matters most: creating exceptional events that resonate with their audience.</p><p>Successful events are built on strong foundations of communication, collaboration, and creativity. By leveraging modern event management solutions, organizers can reduce administrative overhead while increasing attendee satisfaction and engagement.</p>', NULL, NULL, 'pending', NULL, 0, 0, 1, 0, 0, 0, 7, 'Guest Post: Success Stories from Event Organizers - Tech Events Kenya', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', 'events, ticketing, voting, awards', 'media/posts/post-image-4.jpg', 'The event management landscape continues to evolve with new technologies and innovative approaches. Organizations are discovering that creating memora...', NULL, '2026-03-03 17:44:05', '2026-03-03 18:05:45', NULL),
(21, 'c113759e-7bd2-46ed-9862-a0e0008ea1b7', 6, NULL, 2, 13, 'MEMA 2026 — The Gospel Music Awards Gala is Coming to Nairobi!', 'mema-2026-awards-coming-soon', 'The inaugural Myogenic Excellence Music Awards (MEMA) Gala is set for September 16, 2026 in Kisumu, Kenya. Nominations open April 16. Here\'s everything you need to know.', '<p>We are excited to announce the upcoming <strong>Myogenic Excellence Music Awards (MEMA) 2026 Gala</strong> — a landmark celebration of gospel music talent across Kenya and Africa.</p><p>MEMA 2026 is set to take place on <strong>September 16, 2026 in Kisumu, Kenya</strong>, bringing together the finest gospel artists, producers, videographers, and photographers for a night of recognition, music, and excellence.</p><h2>What is MEMA?</h2><p>The Myogenic Excellence Music Awards (MEMA) is a premier platform dedicated to honouring Africa\'s gospel music voices and sounds. From the emerging artist finding their footing to the seasoned producer shaping the industry — MEMA celebrates it all.</p><h2>Award Categories</h2><ul><li>Female Artist of the Year</li><li>Male Artist of the Year</li><li>Emerging Gospel Artist of the Year</li><li>Gospel Song of the Year</li><li>Gospel Video of the Year</li><li>Gospel Collaboration of the Year</li><li>Audio Producer of the Year</li><li>Video Director of the Year</li><li>Photography of the Year</li></ul><h2>Key Dates</h2><ul><li><strong>Nominations Open:</strong> April 16, 2026</li><li><strong>Nominations Close:</strong> July 15, 2026</li><li><strong>Voting Opens:</strong> August 1, 2026</li><li><strong>Voting Closes:</strong> September 14, 2026</li><li><strong>MEMA Gala Night:</strong> September 16, 2026 — Kisumu, Kenya</li></ul><h2>How to Get Involved</h2><p>You can be part of this historic event in three ways:</p><ol><li><strong>Nominate</strong> — Do you know a deserving gospel artist or creative? Nominate them starting April 16 at <a href=\"https://tuqiohub.africa/nominate\" rel=\"noopener noreferrer\" target=\"_blank\">tuqiohub.africa/nominate</a>.</li><li><strong>Vote</strong> — Cast your votes for your favourite nominees from August 1. Each vote costs KES 100, with bundle discounts available.</li><li><strong>Attend</strong> — Get your tickets and join us for the gala night. Early Bird tickets go on sale April 16!</li></ol><p>Stay tuned for more updates. Follow us on social media and visit <a href=\"https://tuqiohub.africa\" rel=\"noopener noreferrer\" target=\"_blank\">tuqiohub.africa</a> for the latest news on MEMA 2026.</p><p><em>Honouring Africa\'s Voices and Sounds.</em></p>', NULL, NULL, 'published', '2026-03-16 06:57:00', 1, 0, 1, 0, 0, 0, 2, 'MEMA 2026 Gospel Music Awards Gala — Kisumu, Kenya', 'The inaugural Myogenic Excellence Music Awards (MEMA) Gala takes place September 16, 2026 in Kisumu. Nominate, vote, and get tickets at tuqiohub.africa.', 'MEMA 2026, gospel music awards, Kisumu, Kenya, gospel awards, MEMA gala', NULL, NULL, NULL, '2026-03-16 06:57:25', '2026-03-26 09:42:44', NULL),
(22, '6708b577-9bba-482b-bcff-647b947e6baa', 6, NULL, 7, 13, 'MEMA 2026 is Coming — Nominations Now Open', 'mema-2026-nominations-open', 'The Myogenic Excellence Music Awards are officially here. Nominations are now open across 8 categories celebrating the best in Kenyan and African gospel music.', '<p>We are thrilled to announce that <strong>MEMA 2026 — the Myogenic Excellence Music Awards</strong> is officially open for nominations!</p><p>This is Kenya\'s first dedicated gospel music awards platform, celebrating outstanding talent across performance, production, videography, and photography.</p><h3>Who Can Be Nominated?</h3><p>Any Kenyan or African gospel artist, producer, director, or photographer who has made a significant impact in 2025–2026 is eligible for nomination. Eight categories are open for public nomination.</p><h3>How to Nominate</h3><p>Visit our <a href=\"/nominate?event=mema-gala-2026\" rel=\"noopener noreferrer\" target=\"_blank\">Nominate page</a>, select the MEMA Gala 2026 event, choose your category, and fill in the nomination form. Nominations are free and open until July 15, 2026.</p><h3>The Gala</h3><p>The MEMA Gala will be held on <strong>September 16, 2026 in Nairobi, Kenya</strong> — an unforgettable evening of music, awards, and celebration.</p><p>Get your tickets early and join us as we celebrate Africa\'s gospel excellence!</p>', 'posts/featured-images/kGDAV9WPCRN9DnasyERx4Zlvss9DGHwyyyANsaav.webp', NULL, 'published', '2026-03-26 09:18:00', 0, 0, 1, 0, 0, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-26 09:18:32', '2026-03-26 10:08:56', NULL),
(23, '7c195839-dda1-4b94-a96c-736edcae1b15', 6, NULL, 5, 13, 'Meet the MEMA 2026 Award Categories — Everything You Need to Know', 'mema-2026-award-categories-guide', 'From Female Artist of the Year to Photography of the Year — here is a full breakdown of all 9 MEMA 2026 award categories and what each one celebrates.', '<p>MEMA 2026 recognises excellence across <strong>9 award categories</strong> covering every dimension of gospel music creation. Here is what each category celebrates:</p><h3>1. Female Artist of the Year</h3><p>Recognising the most impactful female gospel artist of 2026 — an artist whose music, ministry, and influence have resonated with audiences across Kenya and Africa.</p><h3>2. Male Artist of the Year</h3><p>Celebrating outstanding male gospel artistry, ministry impact, and chart performance throughout the year.</p><h3>3. Emerging Gospel Artist of the Year</h3><p>Honouring the brightest new gospel talent on the rise — an artist who broke through in 2025–2026 with fresh sound and genuine ministry.</p><h3>4. Gospel Song of the Year</h3><p>The single gospel track that moved hearts, topped church playlists, and defined the sound of the year.</p><h3>5. Gospel Video of the Year</h3><p>Outstanding visual storytelling in gospel music video production — judged on creativity, production quality, and ministry message.</p><h3>6. Gospel Collaboration of the Year</h3><p>The most memorable gospel partnership — two or more artists coming together for a release that was greater than the sum of its parts.</p><h3>7. Audio Producer of the Year</h3><p>Excellence in gospel music production and sound engineering — the producer behind the hits.</p><h3>8. Video Director of the Year</h3><p>Creative direction and visual mastery in gospel videography — directors who bring gospel songs to stunning visual life.</p><h3>9. Photography of the Year</h3><p>Capturing the soul of gospel music through powerful imagery — event photography, artist portraits, and worship moments.</p><p>Nominations for all 8 public categories are open until July 15, 2026. <a href=\"/nominate?event=mema-gala-2026\" rel=\"noopener noreferrer\" target=\"_blank\">Submit your nomination now →</a></p>', 'posts/featured-images/AbgODRnpS9uRbXPuqbdSmJNo825sAlL4POf7lStp.webp', NULL, 'published', '2026-03-26 09:20:00', 0, 0, 1, 0, 0, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-26 09:20:45', '2026-03-26 10:04:00', NULL),
(24, 'c50ca0af-720b-4e56-b3eb-bec897232a1f', 6, NULL, 1, 13, 'Early Bird Tickets Now Available — MEMA Gala 2026, September 16', 'mema-gala-2026-early-bird-tickets', 'Early bird tickets for the MEMA Gala 2026 are now on sale. Regular seats from KES 1,000 and VIP seats from KES 2,500 — limited quantities, available until June 30.', '<p>The countdown to the most anticipated gospel music event in Kenya has begun. <strong>MEMA Gala 2026</strong> takes place on <strong>September 16, 2026 in Nairobi</strong> — and you can secure your seat today at a special early bird rate.</p><h3>Early Bird Pricing</h3><ul><li><strong>Early Bird Regular Seat</strong> — KES 1,000 (save KES 500 off standard price)</li><li><strong>Early Bird VIP Seat</strong> — KES 2,500 (save KES 1,000 off standard price)</li></ul><p>Early bird tickets are available from April 16 to June 30, 2026. After that, prices revert to standard rates.</p><h3>Standard Pricing (from July 1)</h3><ul><li>Regular Single Seat — KES 1,500</li><li>VIP Single Seat — KES 3,500</li><li>VVIP Single Seat — KES 6,000</li><li>VIP Table (10 seats) — KES 30,000</li><li>VVIP Table (10 seats) — KES 50,000</li></ul><h3>What\'s Included</h3><p>All tickets include a gala dinner and event programme. VIP and VVIP tickets include priority seating. VVIP tickets include VIP lounge access and meet &amp; greet opportunities with award winners.</p><p><a href=\"/event-detail?slug=mema-gala-2026\" rel=\"noopener noreferrer\" target=\"_blank\">Get your tickets now →</a></p>', 'posts/featured-images/mK4IG7kdfXvuDnbHvsVkmpcYiIB4tdp2pt8cusQX.webp', NULL, 'published', '2026-03-26 09:20:00', 0, 0, 1, 0, 0, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-26 09:20:45', '2026-03-26 10:04:45', NULL),
(25, 'b02a53d1-d283-45be-a3d4-348e788e60e5', 6, NULL, 5, 13, 'Why MEMA Matters — The Story Behind Kenya\'s First Gospel Music Awards', 'why-mema-matters-gospel-music-awards-kenya', 'Gospel music has always been the heartbeat of Kenya. But until now, there has been no dedicated national platform to recognise and celebrate its creators. MEMA is changing that.', '<p>Kenya has a rich, vibrant gospel music scene. From worship anthems that fill stadiums to intimate songs that carry people through personal crises — gospel music is woven into the fabric of Kenyan life.</p><p>Yet for too long, the artists, producers, directors, and photographers behind this music have had no dedicated national awards platform to call their own. MEMA is here to change that.</p><h3>What MEMA Stands For</h3><p><strong>Myogenic Excellence Music Awards</strong> — MEMA is built to recognise and celebrate creative excellence in gospel music. Not popularity alone. Not social media follower counts. True artistry, ministry impact, and craft.</p><h3>9 Categories, 36+ Nominees</h3><p>MEMA 2026 spans 9 award categories covering every dimension of gospel music creation — from performing artists to audio producers, video directors, and photographers. Every voice in the gospel music ecosystem deserves recognition.</p><h3>Powered by the Community</h3><p>Unlike industry-only awards, MEMA is driven by public nominations and voting. The Kenyan gospel music community — fans, church communities, music lovers — decides who wins. Eight out of nine categories are open for public nomination and public voting.</p><h3>The MEMA Gala 2026</h3><p>On <strong>September 16, 2026</strong>, Nairobi will host an unforgettable evening of awards, live performances, and celebration. The MEMA Gala is not just an awards night — it is a declaration that African gospel music excellence deserves its own stage.</p><p>Nominate your favourite artists today. Be part of the story. <a href=\"/nominate?event=mema-gala-2026\" rel=\"noopener noreferrer\" target=\"_blank\">Nominate now →</a></p>', 'posts/featured-images/tM3J9fKgek2Jh36hWQAIZMUvLthwyk8NiOoS21qK.webp', NULL, 'published', '2026-03-26 09:20:00', 1, 0, 1, 0, 0, 0, 2, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-26 09:20:45', '2026-03-26 10:07:10', NULL),
(26, '449f4621-f73b-48f1-92b6-de6ac380bffb', 6, NULL, 5, 13, 'How to Vote at MEMA 2026 — A Step-by-Step Guide', 'how-to-vote-mema-2026-guide', 'Voting at MEMA 2026 opens August 1, 2026. Here is a complete guide on how to find nominees, purchase vote bundles, and make your voice count.', '<p>Voting at MEMA 2026 is open to everyone — no registration required. Here\'s how it works:</p><h3>Step 1: Browse the Nominees</h3><p>Visit the <a href=\"/nominees\" rel=\"noopener noreferrer\" target=\"_blank\">Nominees page</a> and browse all shortlisted artists across 9 award categories. Take your time — get to know who has been nominated and what they\'ve achieved.</p><h3>Step 2: Choose Your Vote Bundle</h3><p>MEMA uses a vote bundle system. One vote costs KES 100. You can buy bundles for better value:</p><ul><li>Single Vote — KES 100</li><li>Starter Pack (10 votes) — KES 900</li><li>Fan Pack (50 votes) — KES 4,000 — <strong>Best value!</strong></li><li>Super Fan (100 votes) — KES 7,000</li><li>Champion (500 votes) — KES 30,000</li></ul><h3>Step 3: Pay Securely</h3><p>Complete your payment via M-Pesa or card through our secure payment gateway. Your votes are credited instantly.</p><h3>Step 4: Allocate Your Votes</h3><p>You can spread your votes across multiple nominees and categories. Support the Female Artist AND the Emerging Artist — it\'s your call.</p><h3>When Does Voting Open?</h3><p>Public voting opens on <strong>August 1, 2026</strong> and closes on <strong>September 14, 2026</strong> at 11:59 PM (EAT).</p><p>Mark your calendar — and in the meantime, nominate your favourites so they make it to the voting stage! <a href=\"/nominate?event=mema-gala-2026\" rel=\"noopener noreferrer\" target=\"_blank\">Nominate now →</a></p>', 'posts/featured-images/W0PFc4KhDlkC4SWDg9HkKK49mfhXiuxdSK6FvXFx.webp', NULL, 'published', '2026-03-26 09:20:00', 0, 0, 1, 0, 0, 0, 1, NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-26 09:20:45', '2026-03-26 10:08:18', NULL);

